import org.junit.jupiter.api.Test;

/**
 * The LMDB registry must not silently drift behind the standard logical rewrite catalog: every standard logical rule
 * (SERVICE co-planning, subquery inlining, UNION factoring, GROUP BY equivalences, graph restriction, …) applies to
 * LMDB plans too. Deliberate exclusions belong in {@code DELIBERATE_EXCLUSIONS} with a reason.
 */
class LmdbRuleRegistryCoverageTest {

	private static final Set<String> DELIBERATE_EXCLUSIONS = Set.of();

	@Test
	void lmdbRegistryContainsEveryStandardLogicalRule() {
		Set<String> lmdbRuleIds = LmdbCascadesRuleProvider.rules(new EvaluationStatistics() {
		})
				.rules()
				.stream()
				.map(CascadesRule::id)
				.collect(Collectors.toSet());

		List<String> missing = RuleRegistry.standardLogicalRules()
				.rules()
				.stream()
				.map(CascadesRule::id)
				.distinct()
				.filter(id -> !lmdbRuleIds.contains(id))
				.filter(id -> !DELIBERATE_EXCLUSIONS.contains(id))
				.sorted()
				.collect(Collectors.toList());

		assertEquals(List.of(), missing,
				"Standard logical rewrites missing from the LMDB cascades registry (register them in "
						+ "LmdbCascadesRuleProvider.rules or document a deliberate exclusion here)");
	}

	@Test
	void finiteMembershipDistinctRewriteHasOneReactiveOwner() {
		Set<String> lmdbRuleIds = LmdbCascadesRuleProvider.rules(new EvaluationStatistics())
				.rules()
				.stream()
				.map(CascadesRule::id)
				.collect(Collectors.toSet());

		assertTrue(lmdbRuleIds.contains(LmdbDistinctFiniteMembershipRule.ID), lmdbRuleIds::toString);
		assertFalse(lmdbRuleIds.contains("lmdb-finite-filter-values-distinct-rewrite"),
				"The retired eager GROUP rewrite must not compete with the self-reactivating observer");
		assertFalse(lmdbRuleIds.contains("lmdb-distinct-exists-join"),
				"The retired eager EXISTS rewrite must not bypass transparent semi-join implementations");
	}

	@Test
	void boundLookupImplementationLeavesChildFrontierReactivityToMemoCosting() {
		RuleDescriptor descriptor = new LmdbInnerJoinBoundLookupRule(new EvaluationStatistics()).descriptor();

		assertEquals(Set.of(), descriptor.childPropertiesRead(),
				"The stable join recipe must be recosted, not regenerated, when a child frontier changes");
		assertEquals(Set.of(), descriptor.goalPropertiesRead(),
				"Invocation row counts price child winners; they do not change the physical join recipe");
		assertEquals(Set.of(
				RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED,
				RuleWakeUpEvent.LOGICAL_FACT_CHANGED,
				RuleWakeUpEvent.REQUIRED_PROPERTIES_CHANGED),
				descriptor.wakeUpEvents());
	}

	@Test
	void lmdbOwnedRulesDeclareNarrowSchedulerDependencies() {
		List<String> imprecise = new ArrayList<>();
		Set<String> invocationSensitive = new java.util.TreeSet<>();
		Set<RuleDescriptor.MemoFact> everyFact = EnumSet.allOf(RuleDescriptor.MemoFact.class);

		for (CascadesRule rule : LmdbCascadesRuleProvider.rules(new EvaluationStatistics() {
		}).rules()) {
			if (!(rule instanceof LmdbRule)) {
				continue;
			}
			RuleDescriptor descriptor = rule.descriptor();
			if (descriptor.goalPropertiesRead()
					.contains(RuleDescriptor.GoalProperty.INVOCATION_CARDINALITY)) {
				invocationSensitive.add(rule.id());
			}
			if (descriptor.rootOperators().contains(RuleRootOperator.WILDCARD)) {
				imprecise.add(rule.id() + ": wildcard root operator");
			}
			if (descriptor.factsRead().equals(everyFact)) {
				imprecise.add(rule.id() + ": reads every memo fact");
			}
			if (!descriptor.changesProduced().contains(RuleDescriptor.ProducedChange.PROOF)) {
				imprecise.add(rule.id() + ": emits proofs without declaring proof output");
			}
			if ("lmdb-guarantee-options".equals(rule.id())
					&& descriptor.wakeUpEvents().contains(RuleWakeUpEvent.PROOF_CHANGED)) {
				imprecise.add(rule.id() + ": does not read proofs but wakes on proof changes");
			}
		}

		assertEquals(List.of(), imprecise,
				"LMDB-specific rules must declare finite roots and only the dependencies their matching or application reads");
		assertEquals(Set.of("lmdb-access-path", "lmdb-distinct-cursor-skip", "lmdb-optional-rhs-anchored-lookup",
				"lmdb-row-preserving-subplan-access-path"),
				invocationSensitive,
				"Only LMDB rules that directly estimate an access path from invocation cardinality may retain it");
	}
}
